import toast from "react-hot-toast";

const CategoryMaster = () => {
  const [exams, setExams] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [editId, setEditId] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [isFormOpen, setIsFormOpen] = useState(false);

  const [formData, setFormData] = useState({ 
    catId: "", 
    examId: "", 
    catName: "", 
    features: [] 
  });

  const featureOptions = ["SYLLABUS", "MOCK TEST", "PYQ", "STUDY MATERIAL", "VIDEOS"];

  const fetchData = async () => {
    setLoading(true);
    try {
      const [exRes, catRes, idRes] = await Promise.allSettled([
        axios.get("/master/exam"),
        axios.get("/master/category/all"),
        axios.get("/master/category/next-id")
      ]);

      if (exRes.status === "fulfilled") {
        const examList = Array.isArray(exRes.value.data) ? exRes.value.data : exRes.value.data?.data || [];
        setExams(examList);
      }
      if (catRes.status === "fulfilled") {
        const categoryList = Array.isArray(catRes.value.data) ? catRes.value.data : catRes.value.data?.data || [];
        setCategories(categoryList);
      }
      if (idRes.status === "fulfilled" && idRes.value.data?.nextId && !editId) {
        setFormData((prev) => ({ ...prev, catId: idRes.value.data.nextId }));
      }
    } catch (err) {
      toast.error("DATABASE SYNC FAILED");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const toggleFeature = (feature) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature]
    }));
  };

  const openAddForm = () => {
    setEditId(null);
    setFormData({ catId: "", examId: "", catName: "", features: [] });
    fetchData();
    setIsFormOpen(true);
  };

  const handleEdit = (cat) => {
    setEditId(cat._id);
    setFormData({
      catId: cat.catId,
      examId: cat.examId?._id || "",
      catName: cat.catName,
      features: cat.features || []
    });
    setIsFormOpen(true);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSaving(true);
    try {
      const res = await axios.post("/master/category/upsert", { id: editId, ...formData });
      if (res.data.success) {
        toast.success(editId ? "UPDATED" : "SAVED");
        setIsFormOpen(false);
        fetchData();
      }
    } catch (err) {
      toast.error("SAVE FAILED");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("ARE YOU SURE?")) return;
    try {
      await axios.delete(`/master/category/${id}`);
      toast.success("DELETED");
      fetchData();
    } catch (err) { toast.error("DELETE FAILED"); }
  };

  const filteredCategories = categories.filter(c => 
    c.catName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (c.examId?.examName || "").toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    /* Change 1: Main background changed to a light sky blue tint */
    <div className="min-h-screen bg-[#F0F7FF] p-6 font-sans relative">
      <div className="max-w-7xl mx-auto">
        
        {/* --- HEADER --- */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-600 rounded-2xl text-white shadow-lg shadow-blue-200">
              <Layers size={24} />
            </div>
            <div>
              <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tighter">Category Master</h1>
              <p className="text-[10px] font-bold text-blue-400 uppercase tracking-[0.2em]">Management Portal</p>
            </div>
          </div>

          <button 
            onClick={openAddForm}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-100 transition-all active:scale-95"
          >
            <Plus size={18} strokeWidth={3} />
            Add New Category
          </button>
        </div>

        {/* --- SEARCH --- */}
        <div className="relative mb-6">
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-blue-300" size={20} />
          <input 
            type="text" 
            placeholder="SEARCH RECORDS..."
            /* Change 2: Input background matches sky theme */
            className="w-full pl-14 pr-6 py-4 bg-white border-2 border-blue-50 rounded-[20px] font-black text-sm outline-none focus:border-blue-400 uppercase shadow-sm placeholder:text-blue-200"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        {/* --- TABLE --- */}
        <section className="bg-white rounded-[32px] border border-blue-100 shadow-xl shadow-blue-900/5 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                /* Change 3: Table header shifted from dark slate to deep ocean blue */
                <tr className="bg-[#1E40AF] text-white text-[10px] font-black uppercase tracking-widest">
                  <th className="p-5">ID</th>
                  <th className="p-5">Exam</th>
                  <th className="p-5">Category Name</th>
                  <th className="p-5">Features</th>
                  <th className="p-5 text-center">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-blue-50">
                {loading ? (
                  <tr><td colSpan="5" className="p-20 text-center animate-pulse font-black text-blue-200 uppercase tracking-widest">Fetching Data...</td></tr>
                ) : filteredCategories.map(cat => (
                  /* Change 4: Hover state matches sky theme */
                  <tr key={cat._id} className="hover:bg-blue-50 transition-all">
                    <td className="p-5 font-black text-blue-600 text-xs">{cat.catId}</td>
                    <td className="p-5 font-black text-blue-400 text-[10px] uppercase">{cat.examId?.examName || "---"}</td>
                    <td className="p-5 font-black text-slate-800 text-sm uppercase">{cat.catName}</td>
                    <td className="p-5">
                      <div className="flex flex-wrap gap-1">
                        {cat.features.slice(0, 2).map(f => (
                          <span key={f} className="px-2 py-1 bg-blue-100 text-blue-600 rounded-md text-[8px] font-bold">{f}</span>
                        ))}
                      </div>
                    </td>
                    <td className="p-5 flex justify-center gap-2">
                      <button onClick={() => handleEdit(cat)} className="p-2 bg-blue-50 text-blue-500 rounded-xl hover:bg-blue-500 hover:text-white transition-all">
                        <Edit size={16} />
                      </button>
                      <button onClick={() => handleDelete(cat._id)} className="p-2 bg-red-50 text-red-400 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        {/* --- MODAL FORM --- */}
        {isFormOpen && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-blue-900/20 backdrop-blur-md" onClick={() => setIsFormOpen(false)}></div>
            
            <form 
              onSubmit={handleSubmit}
              className="relative bg-white w-full max-w-xl p-8 rounded-[40px] shadow-2xl border border-blue-50 overflow-hidden"
            >
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">{editId ? "Update" : "New"} Category</h2>
                  <p className="text-[9px] font-bold text-blue-500 uppercase tracking-widest underline decoration-sky-200 decoration-2 underline-offset-4">Exam Master Entry</p>
                </div>
                <button type="button" onClick={() => setIsFormOpen(false)} className="p-2 hover:bg-blue-50 text-blue-400 rounded-full transition-all">
                  <X size={20} />
                </button>
              </div>

              <div className="space-y-5">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="text-[9px] font-black uppercase text-blue-400 mb-1 block">Category ID</label>
                    <div className="flex items-center gap-2 p-3 bg-blue-50/50 border border-blue-100 rounded-xl font-black text-blue-600 text-sm">
                      <Hash size={14} /> {formData.catId || "..."}
                    </div>
                  </div>
                  <div>
                    <label className="text-[9px] font-black uppercase text-blue-400 mb-1 block">Parent Exam</label>
                    <select 
                      required
                      className="w-full p-3 bg-white border border-blue-100 rounded-xl font-black text-xs outline-none focus:border-blue-500 uppercase text-slate-700"
                      value={formData.examId}
                      onChange={(e) => setFormData({...formData, examId: e.target.value})}
                    >
                      <option value="">-- SELECT --</option>
                      {exams.map((ex) => (
                        <option key={ex._id} value={ex._id}>{ex.examName}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div>
                  <label className="text-[9px] font-black uppercase text-blue-400 mb-1 block">Category Name</label>
                  <input 
                    required
                    type="text"
                    className="w-full p-3 border border-blue-100 rounded-xl font-black text-xs outline-none focus:border-blue-500 uppercase text-slate-700"
                    value={formData.catName}
                    onChange={(e) => setFormData({...formData, catName: e.target.value.toUpperCase()})}
                  />
                </div>

                <div>
                  <label className="text-[9px] font-black uppercase text-blue-400 mb-3 block">Available Features</label>
                  <div className="flex flex-wrap gap-2">
                    {featureOptions.map(f => (
                      <button
                        key={f}
                        type="button"
                        onClick={() => toggleFeature(f)}
                        className={`flex items-center gap-2 px-3 py-2 rounded-lg border transition-all font-black text-[9px] ${
                          formData.features.includes(f) 
                          ? "bg-blue-600 border-blue-600 text-white shadow-md shadow-blue-200" 
                          : "bg-white border-blue-100 text-blue-300 hover:border-blue-300"
                        }`}
                      >
                        {formData.features.includes(f) ? <CheckSquare size={12} /> : <Square size={12} />}
                        {f}
                      </button>
                    ))}
                  </div>
                </div>

                <button 
                  disabled={isSaving}
                  className="w-full py-4 mt-2 bg-blue-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all flex justify-center items-center gap-3 active:scale-[0.98]"
                >
                  {isSaving ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                  {editId ? "Update Data" : "Secure Save"}
                </button>
              </div>
            </form>
          </div>
        )}
      </div>
    </div>
  );
};

export default CategoryMaster;
